import React, {useState} from 'react';
import { Container, HeroInnerWrapper, HeroImage, HeroContent } from './styles';
import Dropdown from '../Dropdown';

export default function Hero() {
    const [provinces, setProvinces] = useState(undefined);

    return (
        <Container>
            <HeroInnerWrapper>
                <HeroImage>
                    <img src={require('../assets/images/girl.jpg')} alt="Hero" width="1200" height="675" />
                </HeroImage>
                <HeroContent>
                     <Dropdown
                     placeholder="Select Province"
                     value={provinces}
                     onChange={(v: any) => setProvinces(v)}
                     options={["Alberta",
                         "British Columbia",
                         "Manitoba", "New Brunswick",
                         "Newfoundland",
                         "Northwest Territories",
                     "Nova Scotia",
                     "Ontario",
                     "Prince Edward Island",
                     "Quebec",
                     "Saskatchewan"]}
                     />
                </HeroContent>
            </HeroInnerWrapper>
        </Container>
    );
}
