import React, { useEffect, useState, useRef } from 'react';
import {DropdownContainer, DropdownToggler,DropdownMenu, DropdownMenuList, DropdownMenuItem} from './styles'

interface DropdownProps {
    value: string | null | undefined;
    placeholder: string;
    options: any[];
    onChange: (e: any) => void;
}
const Dropdown = ({ value, options, placeholder = 'Select', onChange }: DropdownProps) => {
    // console.log('Dropdown')
    const node = useRef<HTMLDivElement | null>(null);

    const [open, setOpen] = useState(false);

    const handleChange = (selectedValue: any) => {
        onChange(selectedValue);
        setOpen(false);
    };

    useEffect(() => {
        const handleClick = (e: Event) => {
            e.stopPropagation();
            const target = e.target as HTMLDivElement;
            if (node.current && !node.current.contains(target)) {
                setOpen(false);
            }
        };

        document.addEventListener('mousedown', handleClick);

        return () => {
            document.removeEventListener('mousedown', handleClick);
        };
    }, []);

    return (
        <DropdownContainer ref={node}>
            <DropdownToggler onClick={e => setOpen(!open)} className={open ? 'active': ''}>
                {value || placeholder}
            </DropdownToggler>

            {open && (
                <DropdownMenu className={open ? 'active': ''}>
                    <DropdownMenuList>
                        {options.map((opt: any) => (
                            <DropdownMenuItem onClick={e => handleChange(opt)}>
                                {opt}
                            </DropdownMenuItem>
                        ))}
                    </DropdownMenuList>
                </DropdownMenu>
            )}
        </DropdownContainer>
    );
};

export default Dropdown;
